using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 removed HasIndex for Cosmos (no secondary indexes).
            // entity.HasIndex(b => b.Name); -- removed, was never supported by Cosmos

            // Breaking change 2: Discriminator property renamed from "Discriminator" to "$type".
            // Preserve compatibility with existing documents:
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 3: Id format changed from "EntityType|Key" to just "Key".
            // Preserve compatibility with existing documents:
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<BlogIdGenerator>();
        });
    }
}

// Value generator to preserve the legacy "Blog|{key}" id format
class BlogIdGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry)
        => $"Blog|{Guid.NewGuid()}";
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

