class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: EF 9 uses ReadItem for single-partition queries where possible,
        // but existing raw SQL using c.Discriminator must stay "Discriminator" (not "$type")
        // since we configured HasDiscriminator("Discriminator") above.
        //
        // Any raw SQL like:
        //   SELECT * FROM c WHERE c.Discriminator = 'Blog'
        // remains valid because we kept the legacy discriminator property name.
        //
        // Breaking change 5: Sync over async - SaveChanges now throws by default for Cosmos.
        // Use SaveChangesAsync instead:
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChangesAsync().GetAwaiter().GetResult();
    }
}

